// Fix #3: Validate X-Gateway-Secret header manually instead of using placeholder credential
const secret = $input.item.json.headers?.['x-gateway-secret'] ?? $input.item.json.headers?.['X-Gateway-Secret'] ?? '';
const expectedSecret = $env.GATEWAY_WEBHOOK_SECRET ?? '';
if (!expectedSecret) throw new Error('GATEWAY_WEBHOOK_SECRET env var not set on gateway');
if (secret !== expectedSecret) {
  return [{ json: { _gateway: { valid: false, errors: ['Unauthorized: invalid or missing X-Gateway-Secret header'] } } }];
}
const REQUIRED_TOP = ['id','timestamp','agent','requester','intent','action','risk','policy'];
const REQUIRED_REQUESTER = ['user_id','channel','tenant'];
const REQUIRED_ACTION = ['type','name','target_system','mode'];
const REQUIRED_RISK = ['level'];
const REQUIRED_POLICY = ['policy_set'];
const VALID_ACTION_TYPES = ['workflow','http_call','shell','external_soar'];
const VALID_MODES = ['read-only','read-write','admin'];
const VALID_RISK_LEVELS = ['low','medium','high','critical'];
const VALID_CHANNELS = ['telegram','whatsapp','discord','web','api'];
const ALLOWED_TOP = new Set(['id','timestamp','agent','requester','intent','action','risk','constraints','policy','llm_explanation']);
const errors = [];
const body = $input.item.json.body ?? $input.item.json;
const stripped = {};
for (const key of Object.keys(body)) { if (ALLOWED_TOP.has(key)) stripped[key] = body[key]; }
for (const field of REQUIRED_TOP) { if (!stripped[field]) errors.push(`Missing required field: ${field}`); }
if (stripped.id && !/^[0-9a-f-]{36}$/i.test(stripped.id)) errors.push('Field id must be a UUID v4 string');
if (stripped.requester) {
  for (const f of REQUIRED_REQUESTER) { if (!stripped.requester[f]) errors.push(`Missing requester.${f}`); }
  if (stripped.requester.channel && !VALID_CHANNELS.includes(stripped.requester.channel)) errors.push(`requester.channel must be one of: ${VALID_CHANNELS.join(', ')}`);
}
if (stripped.action) {
  for (const f of REQUIRED_ACTION) { if (!stripped.action[f]) errors.push(`Missing action.${f}`); }
  if (stripped.action.type && !VALID_ACTION_TYPES.includes(stripped.action.type)) errors.push(`action.type must be one of: ${VALID_ACTION_TYPES.join(', ')}`);
  if (stripped.action.mode && !VALID_MODES.includes(stripped.action.mode)) errors.push(`action.mode must be one of: ${VALID_MODES.join(', ')}`);
  if (stripped.action.parameters) {
    for (const [k,v] of Object.entries(stripped.action.parameters)) {
      if (typeof v === 'string' && v.length > 500) errors.push(`action.parameters.${k} exceeds 500 chars — raw prompt injection suspected`);
    }
  }
}
if (stripped.risk) {
  for (const f of REQUIRED_RISK) { if (!stripped.risk[f]) errors.push(`Missing risk.${f}`); }
  if (stripped.risk.level && !VALID_RISK_LEVELS.includes(stripped.risk.level)) errors.push(`risk.level must be one of: ${VALID_RISK_LEVELS.join(', ')}`);
}
if (stripped.policy) {
  for (const f of REQUIRED_POLICY) { if (!stripped.policy[f]) errors.push(`Missing policy.${f}`); }
}
return [{ json: { ...stripped, _gateway: { valid: errors.length === 0, errors } } }];

const item = $('Validate Schema').first().json;
const policyRow = $input.item.json;
if (!policyRow || !policyRow.name) throw new Error(`Policy set '${item.policy?.policy_set}' not found in yaoc2.policy_sets`);
const policySet = {
  name:     policyRow.name,
  version:  policyRow.version,
  defaults: typeof policyRow.defaults === 'string' ? JSON.parse(policyRow.defaults) : (policyRow.defaults ?? {}),
  rules:    typeof policyRow.rules    === 'string' ? JSON.parse(policyRow.rules)    : (policyRow.rules ?? []),
};
return [{ json: { ...item, _policy_set: policySet } }];

// Fix #5: explicit null guard on _policy_set
const item = $input.item.json;
if (!item._policy_set) throw new Error('_policy_set missing from item — Merge Policy node failed silently. Check DB row for policy set: ' + item.policy?.policy_set);
const RISK_ORDER = { low:0, medium:1, high:2, critical:3 };
const action = item.action;
const requester = item.requester;
const risk = item.risk;
const policySet = item._policy_set;
const rules = policySet.rules ?? [];
const defaults = policySet.defaults ?? {};
function matches(ruleVal, actualVal) { if (!ruleVal || ruleVal === '*') return true; return ruleVal === actualVal; }
function meetsRiskThreshold(ruleMinLevel, actualLevel) { if (!ruleMinLevel) return true; return RISK_ORDER[actualLevel] >= RISK_ORDER[ruleMinLevel]; }
function matchesRule(rule, action, requester, risk) {
  const m = rule.match || {};
  return matches(m.target_system, action.target_system)
    && matches(m.action_name, action.name)
    && matches(m.mode, action.mode)
    && matches(m.channel, requester.channel)
    && matches(m.tenant, requester.tenant)
    && meetsRiskThreshold(m.min_risk_level, risk.level);
}
let decision = null, approvers = null, matchedRule = null;
for (const rule of rules) {
  if (matchesRule(rule, action, requester, risk)) {
    decision = rule.decision;
    approvers = rule.approvers ?? null;
    matchedRule = rule.id;
    break;
  }
}
if (!decision) {
  const level = risk.level;
  if (level === 'low' && defaults.auto_allow_low_risk) { decision = 'allow'; matchedRule = '__default_low_allow'; }
  else if (level === 'critical' && defaults.auto_deny_critical_without_approval) { decision = 'deny'; matchedRule = '__default_critical_deny'; }
  else { decision = 'needs-approval'; approvers = { role: defaults.default_approval_role ?? 'threat-analyst', count: 1 }; matchedRule = '__default_needs_approval'; }
}
return [{ json: { ...item, _gateway: { ...item._gateway, decision, approvers, matched_rule: matchedRule } } }];

// Fix #2 + #4: Assemble the full passthrough payload here so executeWorkflow v1.1
// receives it as $input and Normalise Response can read from this node directly.
const SANDBOX_MAP = {
  'ioc_enrichment_misp_opencti': 'HbuaYADHUZWsIFW0',
  'opencti_sync':                'FFdEjxvVkqRIZQ7W',
  'case_create_thehive':         'wKPBXbyhvYMJ8qEH'
};
const item = $input.item.json;
const actionName = item.action?.name;
if (!actionName) throw new Error('action.name is missing');
const sandboxId = SANDBOX_MAP[actionName];
if (!sandboxId) throw new Error(`No sandbox mapped for action.name: ${actionName}. Valid actions: ${Object.keys(SANDBOX_MAP).join(', ')}`);
// Build the exact payload the sandbox executeWorkflowTrigger (passthrough) will receive as $input
return [{ json: {
  proposed_action_id: item.id,
  parameters:         item.action.parameters ?? {},
  action:             item.action,
  requester:          item.requester,
  _original:          item,
  _gateway: {
    ...item._gateway,
    sandbox_workflow_id: sandboxId
  }
} }];

// Fix #4: Read original item from Map to Sandbox (one hop back) not distant Evaluate Policy
const mapItem = $('Map to Sandbox Workflow').first().json;
const original = mapItem._original ?? {};
const gateway = mapItem._gateway ?? {};
const sandboxResult = $input.item.json ?? {};
let finalStatus;
if (sandboxResult.status === 'success') { finalStatus = 'executed'; }
else if (sandboxResult.status === 'partial') { finalStatus = 'executed'; }
else { finalStatus = 'failed'; }
const response = {
  proposed_action_id: original.id,
  final_status:       finalStatus,
  result_summary:     sandboxResult.result_summary ?? 'No result summary',
  raw_result_ref:     sandboxResult.raw_result_ref ?? null
};
const auditRecord = {
  proposed_action_id:  original.id,
  timestamp:           new Date().toISOString(),
  user_id:             original.requester?.user_id,
  display_name:        original.requester?.display_name,
  channel:             original.requester?.channel,
  tenant:              original.requester?.tenant,
  action_type:         original.action?.type,
  action_name:         original.action?.name,
  target_system:       original.action?.target_system,
  action_mode:         original.action?.mode,
  risk_level:          original.risk?.level,
  policy_set:          original.policy?.policy_set,
  decision:            gateway.decision,
  approver_id:         gateway.approver_id ?? null,
  approved_at:         gateway.approved_at ?? null,
  final_status:        finalStatus,
  result_summary:      response.result_summary,
  raw_result_ref:      response.raw_result_ref,
  proposed_action_raw: JSON.stringify(original),
  result_raw:          JSON.stringify(sandboxResult)
};
return [{ json: { response, audit_record: auditRecord } }];

const chatId = $env.APPROVAL_CHAT_ID ?? '';
if (!chatId) throw new Error('APPROVAL_CHAT_ID env var not set on gateway — cannot send approval request');
const item = $input.item.json;
return [{ json: { ...item, _approval_chat_id: chatId } }];

